import { ClientCondition } from '../types';

/* eslint-disable import/prefer-default-export */
export const calculateCondition = (condition: ClientCondition, loginId: string) => {
	if (condition && condition.operator === 'not-empty') {
		const conditionResult = loginId ? condition.met : condition.unmet;
		return {
			startScreenId: conditionResult?.screenId,
			conditionInteractionId: conditionResult?.interactionId
		};
	}
	return {};
};
